                d.old.as_ref().and_then(|e| {
                    blast.get(&(e.file.clone(), e.name.clone(), e.parent.clone())).copied()
                })
            });
            let breaking_boost = if d.breaking { 3.0 } else { 1.0 };
            let files = br.map(|b| (b.direct_files as f64).ln_1p()).unwrap_or(0.0);
            let impact = rank * (files + 1.0) * breaking_boost;
            ReviewEntry {
                diff: d,
                file_rank: rank,
                blast: br,
                impact_score: impact,
            }
        })
        .collect

entry
        .blast
        .map(|b| {
            format!(
                " · blast {}f/{}c/{}t",
                b.direct_files, b.direct_callers, b.transitive_callers
            )
        })
        .unwrap_or_default

by_file
        .iter()
        .map(|(f, es)| {
            let rank = es.first().map(|e| e.file_rank).unwrap_or(0.0);
            (f, rank)
        })
        .collect

enriched
        .iter()
        .map(|e| {
            serde_json::json!({
                "change": change_tag(&e.diff.change),
                "name": e.diff.name,
                "kind": e.diff.kind,
                "file": e.diff.file,
                "breaking": e.diff.breaking,
                "file_rank": e.file_rank,
                "blast": e.blast.map(|b| serde_json::json!({
                    "direct_callers": b.direct_callers,
                    "direct_files": b.direct_files,
                    "transitive_callers": b.transitive_callers,
                })),
                "impact_score": e.impact_score,
            })
        })
        .collect

misses
        .iter()
        .map(|m| {
            serde_json::json!({
                "file": m.file,
                "expected_partner": m.expected_partner,
                "weight": m.weight,
                "support": m.support,
            })
        })
        .collect

order
        .into_iter()
        .map(|key| {
            let (line_start, line_end, sig, overloads, in_test, full_name, rank) =
                groups[&key].clone();
            let (file, parent, kind) = key;
            let line_end = if line_end != line_start {
                Some(line_end)
            } else {
                None
            };
            let name = tail_segment(&full_name).to_string();
            Definition {
                name,
                file,
                line: line_start,
                line_end,
                kind,
                parent,
                sig,
                rank,
                overloads,
                in_test,
            }
        })
        .collect

if pretty {
            serde_json::to_writer_pretty(&mut *output, entity)
        } else {
            serde_json::to_writer(&mut *output, entity)
        }.map_err

if pretty {
            serde_json::to_writer_pretty(&mut *output, reference)
        } else {
            serde_json::to_writer(&mut *output, reference)
        }.map_err

